#:property AllowUnsafeBlocks=true

Span<nint> span = stackalloc nint[5];
for (int i = 0; i < span.Length; i++)
    span[i] = i * 10;

Console.WriteLine("stackalloc Span<nint>:");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  span[{i}] = {span[i]}");

Console.WriteLine($"\nnint size: {sizeof(nint)} bytes");
Console.WriteLine("Success — stackalloc Span<nint> works!");

